Actionscript.script:
this._lockroot = false;
this._visible = false;
stop();
音效播放器 = new Array(6);
播放时间记录 = new Object();
同时播放数量 = 6;
播放间隔帧 = 2;
frame = 0;
playindex = 0;

for (var i = 0; i < 同时播放数量; i++)
{
	var container = this.createEmptyMovieClip("container" + i, this.getNextHighestDepth());
	音效播放器[i] = container;
}

function 播放音效(音效id, 音量乘数, 声音源)
{
	if(frame - 播放时间记录[音效id] < 播放间隔帧){
		return false;
	}
	var sound = new Sound(音效播放器[playindex]);
	sound.attachSound(音效id);
	音量乘数 = (音量乘数 >= 1 or 音量乘数 <= 0) ? 1 : 音量乘数;
	var 音量 = Math.floor(音量乘数 * _root.音效音量);
	音量 = Math.max(音量, 1);
	sound.setVolume(音量);
	sound.start(0,1);
	playindex = (playindex + 1) % 同时播放数量;
	播放时间记录[音效id] = frame;
	return true;
}

this.onEnterFrame = function(){
	frame ++;
}
